document.addEventListener("DOMContentLoaded",function(){const n=document.querySelector(".nav-toggle"),s=document.querySelector(".nav-menu");n&&s&&n.addEventListener("click",function(){const e=this.getAttribute("aria-expanded")==="true";this.setAttribute("aria-expanded",!e),s.classList.toggle("is-open")}),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){const t=this.getAttribute("href");if(!t||!t.startsWith("#")||t==="#"||t.length<2)return;e.preventDefault();const n=document.querySelector(t);n&&n.scrollIntoView({behavior:"smooth"})})});const t=document.querySelector(".site-header");t&&window.addEventListener("scroll",function(){window.scrollY>10?t.classList.add("is-scrolled"):t.classList.remove("is-scrolled")});const e=document.getElementById("featured-cities-grid");if(e){const t=Array.from(e.children);for(let n=t.length-1;n>0;n--){const s=Math.floor(Math.random()*(n+1));e.appendChild(t[s])}Array.from(e.children).forEach(function(e,t){e.style.display=t<8?"":"none"})}})